for fp in files:
    try:
        with open(fp, 'r') as f:
            content = f.read()
    except:
        continue
    slug = fp.split('/')[1]
    all_entries.append({'slug': slug, 'content': content})

# Phase transitions with regex
phase_transitions = Counter()
for e in all_entries:
    matches = re.findall(r'__Old Status:\*\*\s*(.*?)(?:\n|$).*?__New Status:\*\*\s*(.*?)(?:\n|$)', e['content'], re.DOTALL)
    if not matches:
        matches = re.findall(r'Old Status:\s*(.*?)(?:\n|$).*?New Status:\s*(.*?)(?:\n|$)', e['content'], re.DOTALL)
    for old, new in matches:
        old_clean = old.strip().rstrip('*').strip()
        new_clean = new.strip().rstrip('*').strip()
        if old_clean and new_clean:
            phase_transitions[(old_clean, new_clean)] += 1

print("=== PHASE TRANSITIONS ===")
for (old, new), cnt in phase_transitions.most_common(20):
    print(f"  '{old}' -> '{new}': {cnt}")

