import os, re
from collections import Counter, defaultdict

with open('/tmp/batch2_2_files.txt') as f:
    files = [line.strip() for line in f if line.strip()]

# Read all content
all_entries = []
for fp in files:
    try:
        with open(fp, 'r') as f:
            content = f.read()
    except:
        continue
    slug = fp.split('/')[1]
    all_entries.append({'slug': slug, 'content': content, 'file': fp})

# ========= DETAILED PATTERN EXTRACTION =========

# 1. Negotiation patterns - extract specific offer/counter details
nego_details = []
for e in all_entries:
    c = e['content']
    # Look for specific offer amounts
    offers = re.findall(r'offer.*?\$[\d,]+', c, re.IGNORECASE)
    counters = re.findall(r'counter.*?\$[\d,]+', c, re.IGNORECASE)
    settled = re.findall(r'settled? (?:at|for).*?\$[\d,]+', c, re.IGNORECASE)
    if offers or counters or settled:
        nego_details.append({
            'slug': e['slug'],
            'offers': offers,
            'counters': counters,
            'settled': settled
        })

# 2. PIP specifics
pip_details = defaultdict(set)
for e in all_entries:
    lower = e['content'].lower()
    if 'pip ledger' in lower:
        pip_details['ledger_request'].add(e['slug'])
    if 'pip claim' in lower or 'pip setup' in lower:
        pip_details['claim_setup'].add(e['slug'])
    if 'pip paid' in lower or 'pip payment' in lower:
        pip_details['payment'].add(e['slug'])
    if 'pip exhaust' in lower or 'no more pip' in lower:
        pip_details['exhaustion'].add(e['slug'])
    if 'direction to pay' in lower or 'dtp' in lower:
        pip_details['direction_to_pay'].add(e['slug'])

# 3. Settlement amounts (anonymized ranges)
settlement_amounts = []
for e in all_entries:
    amounts = re.findall(r'\$(\d{1,3}(?:,\d{3})*(?:\.\d{2})?)', e['content'])
    for a in amounts:
        try:
            val = float(a.replace(',', ''))
            if 500 <= val <= 200000:
                settlement_amounts.append((e['slug'], val))
        except:
            pass

# 4. Liability dispute patterns
liability_disputes = set()
for e in all_entries:
    lower = e['content'].lower()
    if any(x in lower for x in ['denied liability', 'liability denied', 'denying liability', 'disputed liability', 'at-fault']):
        liability_disputes.add(e['slug'])

# 5. Recorded statement patterns
recorded_statement = set()
for e in all_entries:
    lower = e['content'].lower()
    if 'recorded statement' in lower:
        recorded_statement.add(e['slug'])

# 6. EvenUp usage
evenup_cases = set()
for e in all_entries:
    if 'evenup' in e['content'].lower() or 'even up' in e['content'].lower():
        evenup_cases.add(e['slug'])

# 7. ZipLiens
zipliens_cases = set()
for e in all_entries:
    if 'zipliens' in e['content'].lower() or 'zip liens' in e['content'].lower():
        zipliens_cases.add(e['slug'])

# 8. Check issuance patterns
check_cases = set()
for e in all_entries:
    if 'check #' in e['content'].lower() or 'mailed check' in e['content'].lower():
        check_cases.add(e['slug'])

# 9. Phase transition details  
phase_data = []
for e in all_entries:
    # Parse all phase changes 
    changes = re.findall(r'Phase Changed?:?\s*(\w[\w\s]*?)(?:\n|$)', e['content'])
    for ch in changes:
        phase_data.append((e['slug'], ch.strip()))

# 10. LOR (Letter of Representation) patterns
lor_cases = set()
for e in all_entries:
    if 'lor ' in e['content'].lower() or 'letter of rep' in e['content'].lower():
        lor_cases.add(e['slug'])

# 11. Welcome call patterns
welcome_call_cases = set()
for e in all_entries:
    if 'welcome call' in e['content'].lower():
        welcome_call_cases.add(e['slug'])

# 12. Case types from case-type fields 
case_types = Counter()
for e in all_entries:
    m = re.findall(r'Case Type.*?\n(.*?)(?:\n|$)', e['content'])
    for t in m:
        case_types[t.strip()] += 1

print("=== NEGOTIATION DETAILS ===")
print(f"Cases with offer amounts: {len(nego_details)}")
for d in nego_details[:10]:
    print(f"  [{d['slug']}] Offers: {d['offers'][:3]} | Counters: {d['counters'][:3]} | Settled: {d['settled'][:3]}")

print(f"\n=== PIP DETAILS ===")
for k, v in pip_details.items():
    print(f"  {k}: {len(v)} cases")

print(f"\n=== LIABILITY DISPUTES: {len(liability_disputes)} ===")
for s in sorted(liability_disputes):
    print(f"  {s}")

print(f"\n=== RECORDED STATEMENTS: {len(recorded_statement)} ===")
print(f"=== EVENUP: {len(evenup_cases)} -> {evenup_cases} ===")
print(f"=== ZIPLIENS: {len(zipliens_cases)} -> {zipliens_cases} ===")
print(f"=== CHECK ISSUANCE: {len(check_cases)} ===")
print(f"=== LOR: {len(lor_cases)} ===")
print(f"=== WELCOME CALL: {len(welcome_call_cases)} ===")

print(f"\n=== PHASE CHANGES ===")
phase_counts = Counter()
for slug, ph in phase_data:
    phase_counts[ph] += 1
for k, v in phase_counts.most_common(20):
    print(f"  '{k}': {v}")

print(f"\n=== SETTLEMENT VALUE RANGES ===")
vals = [v for _, v in settlement_amounts]
if vals:
    print(f"  Total amounts found: {len(vals)}")
    print(f"  <$5K: {sum(1 for v in vals if v < 5000)}")
    print(f"  $5K-$15K: {sum(1 for v in vals if 5000 <= v < 15000)}")
    print(f"  $15K-$50K: {sum(1 for v in vals if 15000 <= v < 50000)}")
    print(f"  >$50K: {sum(1 for v in vals if v >= 50000)}")

